import { useState, useEffect, useCallback, useRef } from "react";
import { JOBS, APPS_SEED, INITIAL_USERS } from "./data/jobs";
import { injectStyles }             from "./utils/styles";
import { useToast }                 from "./hooks/useToast";

import Navbar           from "./components/Navbar";
import Footer           from "./components/Footer";
import { Toast }        from "./components/UI";

import AuthPage         from "./pages/AuthPage";
import HomePage         from "./pages/HomePage";
import JobsPage         from "./pages/JobsPage";
import JobDetailPage    from "./pages/JobDetailPage";
import AboutPage        from "./pages/AboutPage";
import ContactPage      from "./pages/ContactPage";
import MyAppsPage       from "./pages/MyAppsPage";
import AdminDashboard   from "./pages/AdminDashboard";
import ProfilePage      from "./pages/ProfilePage";

const API_URL  = "http://localhost:5000/api";
const LS_USERS = "catalyst_users";
const LS_APPS  = "catalyst_apps";
const LS_JOBS  = "catalyst_jobs";
const LS_USER  = "catalyst_user";
const LS_TOKEN = "catalyst_token";
const BC_NAME  = "catalyst_sync";       // BroadcastChannel name

/* ── Helpers ─────────────────────────────────────────────────── */
const load = (key, fallback) => { try { const v = localStorage.getItem(key); return v ? JSON.parse(v) : fallback; } catch { return fallback; } };
const save = (key, val)      => { try { localStorage.setItem(key, JSON.stringify(val)); } catch {} };


export default function App() {
  useEffect(() => injectStyles(), []);

  const [page,    setPage]    = useState("home");
  const [jobId,   setJobId]   = useState(null);
  const [authMode,setAuthMode] = useState(null);
  const [user,    setUser]    = useState(() => load(LS_USER, null));

  // Persist everything to localStorage so admin always sees latest data
  const [jobs,   setJobsFn]   = useState(() => load(LS_JOBS,  JOBS));
  const [apps,   setAppsFn]   = useState(() => load(LS_APPS,  APPS_SEED));
  const [users,  setUsersFn]  = useState(() => load(LS_USERS, INITIAL_USERS));

  const toast = useToast();

  // Wrap setters to auto-persist on every change AND broadcast to other tabs
  const bc = useRef(null);
  useEffect(() => {
    try { bc.current = new BroadcastChannel(BC_NAME); } catch {}
    return () => { try { bc.current?.close(); } catch {} };
  }, []);

  const broadcast = useCallback((type, data) => {
    try { bc.current?.postMessage({ type, data }); } catch {}
  }, []);

  const setJobs  = useCallback(updater => setJobsFn(prev  => { const next = typeof updater === "function" ? updater(prev)  : updater; save(LS_JOBS,  next); broadcast("jobs",  next); return next; }), [broadcast]);
  const setApps  = useCallback(updater => setAppsFn(prev  => { const next = typeof updater === "function" ? updater(prev)  : updater; save(LS_APPS,  next); broadcast("apps",  next); return next; }), [broadcast]);
  const setUsers = useCallback(updater => setUsersFn(prev => { const next = typeof updater === "function" ? updater(prev)  : updater; save(LS_USERS, next); broadcast("users", next); return next; }), [broadcast]);

  // Listen for changes broadcast from other tabs (admin → user tabs)
  useEffect(() => {
    const handler = msg => {
      if (!msg?.data?.type) return;
      if (msg.data.type === "jobs")  setJobsFn(msg.data.data);
      if (msg.data.type === "apps")  setAppsFn(msg.data.data);
      if (msg.data.type === "users") setUsersFn(msg.data.data);
    };
    try { bc.current?.addEventListener("message", handler); }
    catch {}
    // Also listen for storage events (handles separate windows)
    const storageHandler = e => {
      if (e.key === LS_JOBS  && e.newValue) setJobsFn(JSON.parse(e.newValue));
      if (e.key === LS_APPS  && e.newValue) setAppsFn(JSON.parse(e.newValue));
      if (e.key === LS_USERS && e.newValue) setUsersFn(JSON.parse(e.newValue));
    };
    window.addEventListener("storage", storageHandler);
    return () => {
      try { bc.current?.removeEventListener("message", handler); } catch {}
      window.removeEventListener("storage", storageHandler);
    };
  }, []);

  /* ── Try to sync with backend (optional - graceful fallback) ─ */
  useEffect(() => {
    const syncBackend = async () => {
      try {
        const jRes = await fetch(`${API_URL}/jobs`);
        if (jRes.ok) { const d = await jRes.json(); if (d?.length) setJobs(d); }

        const token = localStorage.getItem(LS_TOKEN);
        const usr   = load(LS_USER, null);
        if (token && usr) {
          const endpoint = usr.role === "admin" ? "/apps/all" : "/apps/user";
          const aRes = await fetch(`${API_URL}${endpoint}`, { headers: { "Authorization": `Bearer ${token}` } });
          if (aRes.ok) { const d = await aRes.json(); if (d?.length) setApps(d); }

          if (usr.role === "admin") {
            const uRes = await fetch(`${API_URL}/users/all`, { headers: { "Authorization": `Bearer ${token}` } });
            if (uRes.ok) { const d = await uRes.json(); if (d?.length) setUsers(d); }
          }
        }
      } catch {
        // Backend not available — use localStorage data (already loaded)
      }
    };
    syncBackend();
  }, []); // eslint-disable-line

  /* ── Navigation ───────────────────────────────────────────── */
  const nav = (p, id) => {
    setPage(p);
    if (id !== undefined) setJobId(id);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  /* ── Auth ─────────────────────────────────────────────────── */
  const login = (u, token) => {
    setUser(u);
    save(LS_USER, u);
    if (token) save(LS_TOKEN, token);

    // Register the new/returning user in the admin user list if not already there
    setUsers(prev => {
      const exists = prev.some(x => x.email === u.email);
      if (exists) return prev;
      const newUser = {
        id:     Date.now(),
        name:   u.name || u.email.split("@")[0],
        email:  u.email,
        role:   u.role || "user",
        status: "Approved",
        joined: new Date().toISOString().split("T")[0],
        uid:    u.uid || null,
      };
      return [...prev, newUser];
    });

    setAuthMode(null);
    nav(u.role === "admin" ? "admin" : "home");
    toast.add(`Welcome${u.name ? `, ${u.name}` : ""}! 👋`, "success");
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem(LS_USER);
    localStorage.removeItem(LS_TOKEN);
    nav("home");
    toast.add("Signed out successfully.", "success");
  };

  const updateProfile = data => {
    const updated = { ...user, ...data };
    setUser(updated);
    save(LS_USER, updated);
    setUsers(us => us.map(u => u.email === updated.email ? { ...u, ...data } : u));
  };

  /* ── User Management (Admin) ──────────────────────────────── */
  const updateUserStatus  = (id, status) => setUsers(us => us.map(u => u.id === id ? { ...u, status } : u));
  const deleteUser        = id           => setUsers(us => us.filter(u => u.id !== id));
  const resetUserPassword = _id          => toast.add("Password reset email sent.", "info");

  /* ── Job Application ──────────────────────────────────────── */
  const apply = async data => {
    const job = jobs.find(j => j.id === data.jobId);
    const newApp = {
      id:        Date.now(),
      job_id:    data.jobId,
      jobId:     data.jobId,
      jobTitle:  job?.title || data.jobTitle || "Unknown",
      name:      data.name,
      email:     data.email,
      phone:     data.phone,
      experience:data.exp   || "",
      exp:       data.exp   || "",
      resume_url:data.resume ? (data.resume.name || data.resume) : "",
      status:    "Applied",
      timeline:  ["Applied"],
      date:      new Date().toISOString().split("T")[0],
      applied_at:new Date().toISOString(),
    };

    // Optimistic update — immediately visible everywhere (including admin)
    setApps(prev => [...prev, newApp]);
    toast.add("Application submitted! 🎉", "success");
    nav("myapps");

    // Try to persist to backend (optional)
    try {
      const token = localStorage.getItem(LS_TOKEN);
      if (token) {
        await fetch(`${API_URL}/apps`, {
          method:  "POST",
          headers: { "Content-Type": "application/json", "Authorization": `Bearer ${token}` },
          body:    JSON.stringify(newApp),
        });
      }
    } catch { /* Backend not available, localStorage already saved */ }
  };

  /* ── Status Update (Admin → reflects in candidate view) ───── */
  const updateStatus = async (id, status) => {
    const appItem = apps.find(a => a.id === id);
    if (!appItem) return;
    const timeline = [...new Set([...(appItem.timeline || appItem.tl || ["Applied"]), status])];

    // Instant update across all views
    setApps(prev => prev.map(x => x.id !== id ? x : { ...x, status, timeline, tl: timeline }));

    // Try backend sync
    try {
      const token = localStorage.getItem(LS_TOKEN);
      if (token) {
        await fetch(`${API_URL}/apps/${id}/status`, {
          method:  "PUT",
          headers: { "Content-Type": "application/json", "Authorization": `Bearer ${token}` },
          body:    JSON.stringify({ status, timeline }),
        });
      }
    } catch { /* silently fail */ }
  };

  /* ── Job CRUD (Admin) ─────────────────────────────────────── */
  const addOrUpdateJob = job => setJobs(js => {
    const exists = js.find(x => x.id === job.id);
    return exists ? js.map(x => x.id === job.id ? job : x) : [...js, { ...job, id: job.id || Date.now() }];
  });
  const deleteJob = id => setJobs(js => js.filter(j => j.id !== id));

  const selectedJob = jobs.find(j => j.id === jobId);

  /* ── Full-screen Auth view ────────────────────────────────── */
  if (authMode) {
    return (
      <>
        <AuthPage mode={authMode} onBack={() => setAuthMode(null)} onLogin={login} toast={toast} />
        <Toast items={toast.items} rm={toast.rm} />
      </>
    );
  }

  return (
    <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column" }}>
      <Navbar page={page} nav={nav} user={user} openAuth={m => setAuthMode(m)} doLogout={logout} />

      <div style={{ flex: 1 }}>
        {page === "home"    && <HomePage     jobs={jobs} nav={nav} openAuth={m => setAuthMode(m)} />}
        {page === "jobs"    && <JobsPage     jobs={jobs} nav={nav} />}
        {page === "job"     && <JobDetailPage job={selectedJob} nav={nav} onApply={apply} user={user} openAuth={m => setAuthMode(m)} />}
        {page === "about"   && <AboutPage />}
        {page === "contact" && <ContactPage  toast={toast} />}
        {page === "myapps"  && <MyAppsPage   apps={apps.filter(a => a.email === user?.email)} user={user} />}
        {page === "profile" && <ProfilePage  user={user} onUpdateProfile={updateProfile} toast={toast} />}

        {page === "admin" && user?.role === "admin" && (
          <AdminDashboard
            jobs={jobs}  apps={apps}  users={users}
            onUpdateStatus={updateStatus}
            onUpdateUserStatus={updateUserStatus}
            onDeleteUser={deleteUser}
            onResetUserPassword={resetUserPassword}
            onAddJob={addOrUpdateJob}
            onDeleteJob={deleteJob}
            toast={toast}
          />
        )}
        {page === "admin" && user?.role !== "admin" && (
          <div style={{ textAlign: "center", padding: 80 }}>
            <div style={{ fontSize: 52 }}>🔒</div>
            <div style={{ fontWeight: 700, fontSize: 20, marginTop: 16 }}>Admin access required</div>
          </div>
        )}
      </div>

      <Footer nav={nav} onAdminAccess={() => setAuthMode("admin")} />
      <Toast items={toast.items} rm={toast.rm} />
    </div>
  );
}
